import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Empty / minimal cases
  it.todo("returns only the processing fee (5 G) for an empty item list");

  // Base premium per main item type
  it.todo("quotes a plain sword: 100 G base + 5 G fee = 105 G");
  it.todo("quotes a plain amulet: 60 G base + 5 G fee = 65 G");
  it.todo("quotes a plain staff: 80 G base + 5 G fee = 85 G");
  it.todo("quotes a plain potion: 40 G base + 5 G fee = 45 G");

  // Components and building blocks
  it.todo("quotes 2 runes at 25 G each: 50 G base + 5 G fee = 55 G");
  it.todo("quotes 3 runes as a building block: 60 G base + 5 G fee = 65 G");
  it.todo("quotes 4 runes (no block): 100 G base + 5 G fee = 105 G");
  it.todo("quotes 7 runes (one block of 3 + 4 singles): 175 G base + 5 G fee = 180 G");
  it.todo("quotes 2 runes + 1 moonstone (no block, different types): 75 G base + 5 G fee = 80 G");
  it.todo("quotes 3 runes + 3 moonstones (two separate blocks): 120 G base + 5 G fee = 125 G");

  // Item-level modifiers
  it.todo("adds 50% curse surcharge to a cursed sword's base premium");
  it.todo("adds 30% high-enchantment surcharge for enchantment exactly 5");
  it.todo("does not add high-enchantment surcharge for enchantment 4");
  it.todo("stacks curse and high-enchantment surcharges on the same item");

  // Multi-item modifier scoping
  it.todo("applies curse surcharge only to the cursed item in a multi-item policy");

  // Policy-level modifiers
  it.todo("applies 20% loyalty discount for customer with exactly 2 years with MHPCO");
  it.todo("applies 10% first-insurance surcharge on every item of a quote");
  it.todo("applies 15% follow-up contract discount on second+ quote");

  // Integration examples from prompt
  it.todo("newcomer cursed sword example yields 165 G");
  it.todo("long-standing customer's second contract cursed enchanted sword yields 160 G");

  // Rounding
  it.todo("rounds premium up in MHPCO's favor (197.5 → 198)");
  it.todo("rounds payout down in MHPCO's favor (350.5 → 350)");

  // Claim processing - basic
  it.todo("pays out damage minus 100 G deductible for a standard sword");
  it.todo("pays out rune damage minus 100 G deductible (no special clause)");
  it.todo("reimburses dragon-material item in full, then applies deductible");
  it.todo("reimburses high-enchantment (≥8) item at 50%, then applies deductible");
  it.todo("with both dragon material and high enchantment, 50% rule wins then deductible");
  it.todo("applies deductible once per damaged item in a multi-item incident");

  // Multiple items of same type
  it.todo("handles two swords as two separate insurances and two separate deductibles");
  it.todo("rejects claim if damages contains more entries of a type than the policy covers");

  // Validation / error cases
  it.todo("rejects quote with unknown item type");
  it.todo("rejects claim referencing item not in the policy");
  it.todo("rejects claim with negative damage amount");
});

