type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const itemBasePremium = (item: Item): number => {
  return BASE_PREMIUM[item.type];
};

const computeQuotePremium = (items: Item[]): number => {
  const policyBase = items.reduce((sum, item) => sum + itemBasePremium(item), 0);
  const firstInsurance = items.reduce(
    (sum, item) => sum + itemBasePremium(item) * FIRST_INSURANCE_SURCHARGE,
    0
  );
  const total = policyBase + firstInsurance + PROCESSING_FEE;
  return Math.ceil(total);
};

export const runScenario = (input: Scenario): { results: Array<{ premium: number }> } => {
  const results = input.steps.map((step) => ({ premium: computeQuotePremium(step.items) }));
  return { results };
};

