type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PRICE = 60;

const MAIN_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_BASE_PREMIUM: Record<string, number> = {
  rune: 25,
};

const isComponent = (type: string): boolean => type in COMPONENT_BASE_PREMIUM;

const groupBaseForComponents = (componentItems: Item[]): number => {
  const countsByType = new Map<string, number>();
  for (const item of componentItems) {
    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
  }
  let total = 0;
  for (const [type, count] of countsByType) {
    const singlePrice = COMPONENT_BASE_PREMIUM[type];
    const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
    const remainder = count % COMPONENT_BLOCK_SIZE;
    total += blocks * COMPONENT_BLOCK_PRICE + remainder * singlePrice;
  }
  return total;
};

const itemBaseEntries = (items: Item[]): number[] => {
  const componentItems = items.filter((i) => isComponent(i.type));
  const mainItems = items.filter((i) => !isComponent(i.type));
  const entries: number[] = mainItems.map((i) => MAIN_BASE_PREMIUM[i.type]);
  if (componentItems.length > 0) entries.push(groupBaseForComponents(componentItems));
  return entries;
};

const computeQuotePremium = (items: Item[]): number => {
  const itemBases = itemBaseEntries(items);
  const policyBase = itemBases.reduce((sum, base) => sum + base, 0);
  const firstInsurance = itemBases.reduce((sum, base) => sum + base * FIRST_INSURANCE_SURCHARGE, 0);
  const total = policyBase + firstInsurance + PROCESSING_FEE;
  return Math.ceil(total);
};

export const runScenario = (input: Scenario): { results: Array<{ premium: number }> } => {
  const results = input.steps.map((step) => ({ premium: computeQuotePremium(step.items) }));
  return { results };
};

