  const mainItems = items.filter((i) => !isComponent(i.type));
  const entries: number[] = mainItems.map((i) => MAIN_BASE_PREMIUM[i.type]);
  if (componentItems.length > 0) entries.push(groupBaseForComponents(componentItems));
  return entries;
};

const computeQuotePremium = (items: Item[]): number => {
  const itemBases = itemBaseEntries(items);
  const policyBase = itemBases.reduce((sum, base) => sum + base, 0);
  const firstInsurance = itemBases.reduce((sum, base) => sum + base * FIRST_INSURANCE_SURCHARGE, 0);
  const total = policyBase + firstInsurance + PROCESSING_FEE;
  return Math.ceil(total);
};

export const runScenario = (input: Scenario): { results: Array<{ premium: number }> } => {
  const results = input.steps.map((step) => ({ premium: computeQuotePremium(step.items) }));
  return { results };
};

