type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PRICE = 60;

const MAIN_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_BASE_PREMIUM: Record<string, number> = {
  rune: 25,
};

const isComponent = (type: string): boolean => type in COMPONENT_BASE_PREMIUM;

const componentGroupBase = (count: number, singlePrice: number): number => {
  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PRICE;
  return count * singlePrice;
};

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const policyBase = (items: Item[]): number => {
  const components = items.filter((i) => isComponent(i.type));
  const mains = items.filter((i) => !isComponent(i.type));
  const mainsTotal = mains.reduce((s, i) => s + MAIN_BASE_PREMIUM[i.type], 0);
  let componentsTotal = 0;
  for (const [type, count] of countByType(components)) {
    componentsTotal += componentGroupBase(count, COMPONENT_BASE_PREMIUM[type]);
  }
  return mainsTotal + componentsTotal;
};

const computeQuotePremium = (items: Item[]): number => {
  const base = policyBase(items);
  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE;
  const total = base + firstInsurance + PROCESSING_FEE;
  return Math.ceil(total);
};

export const runScenario = (input: Scenario): { results: Array<{ premium: number }> } => {
  const results = input.steps.map((step) => ({ premium: computeQuotePremium(step.items) }));
  return { results };
};

