  it.todo("applies 10% first-insurance surcharge on every item of a quote");
  it.todo("applies 15% follow-up contract discount on second+ quote");

  // Integration examples from prompt
  it.todo("newcomer cursed sword example yields 165 G");
  it.todo("long-standing customer's second contract cursed enchanted sword yields 160 G");

  // Rounding
  it.todo("rounds premium up in MHPCO's favor (197.5 → 198)");
  it.todo("rounds payout down in MHPCO's favor (350.5 → 350)");

  // Claim processing - basic
  it.todo("pays out damage minus 100 G deductible for a standard sword");
  it.todo("pays out rune damage minus 100 G deductible (no special clause)");
  it.todo("reimburses dragon-material item in full, then applies deductible");
  it.todo("reimburses high-enchantment (≥8) item at 50%, then applies deductible");
  it.todo("with both dragon material and high enchantment, 50% rule wins then deductible");
  it.todo("applies deductible once per damaged item in a multi-item incident");

  // Multiple items of same type
  it.todo("handles two swords as two separate insurances and two separate deductibles");
  it.todo("rejects claim if damages contains more entries of a type than the policy covers");

